const Q_GEOGRAPHY_2012=[{"id": "objective>Geography>2012>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Economics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CRK</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Geography</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject is Geography and not other options listed.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2012>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The scale of the map expressed as a representative fraction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">25000</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">50000</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">75000</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100000</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1cm on the map represent 1km on ground, since 1km = 100,000 cm, the scale will be 1:100,000.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2012>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The feature marked Q is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sandpit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">headland</div>", "<div style=\"font-family:Cambria;font-size:17px;\">valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spur</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The apex of the higher 'U' shaped contour points to the next lower one.</div>", "topic": "PRATICAL GEOGRAPHY I : MAP READING AND INTERPRETATION"}, {"id": "objective>Geography>2012>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The predominant occupation of the inhabitants of the area is likely to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">farming</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lumbering</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fishing</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Forest/Trees are scattered all over the map area. The predominant occupation of the inhabitants of the area is likely to be </div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2012>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong><em>Use the map below to answer this question</em></strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The distribution of settlements in the area is mostly influenced by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">roads</div>", "<div style=\"font-family:Cambria;font-size:17px;\">minerals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gradies</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vegetation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Settlement avoided steep slope areas. The distribution of settlements in the area is mostly influenced by roads.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2012>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The length between two points on a topographical map is 5cm. What is the actual distance between them if the scale of the map is 1:50000?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.5km</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.0km</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The scale of the map is 1:50000, which means 1cm on the map represents 50000cm (or 0.5km) in reality. Therefore, if the length between two points on the map is 5cm, the actual distance between them would be 5cm * 0.5km/cm = 2.5km. Hence, option 1 is correct.</div>", "topic": "PRATICAL GEOGRAPHY I : SCALE AND MEASUREMENT DISTANCES"}, {"id": "objective>Geography>2012>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The percentage of diamond produced by 'Other' is approximately</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.38%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.80%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.00%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10.26%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">4,360/42,500 × 100  <br/>  = 10.26% <br/> The percentage of diamond produced by 'Other' is approximately 10.26%</div>", "topic": "PRATICAL GEOGRAPHY II : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2012>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the pie chart, Zaire accounts for about </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">105<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">107<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">108<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">111<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">12,800/42,500 × 360°  <br/>  = 108° <br/> In the pie chart, Zaire accounts for about 108°</div>", "topic": "PRATICAL GEOGRAPHY II : MINERAL EXPLOITATION"}, {"id": "objective>Geography>2012>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chain survey is most convenient for measurement on </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rocky environments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">embarkments</div>", "<div style=\"font-family:Cambria;font-size:17px;\">irregular slopes</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chain survey is a method of surveying in which only linear measurements are made in the field. It is most convenient for measurement on flat or plain terrain where there are fewer obstacles. Hence, option 2 is correct.</div>", "topic": "PRATICAL GEOGRAPHY I : ELEMENTARY SURVEYING CHAIN AND PRISMATIC"}, {"id": "objective>Geography>2012>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The earth's crust consists essentially of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium and silica</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silica and aluminium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">calcium and aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium and calcium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The earth's crust is primarily composed of rocks which are made up of minerals. The most abundant minerals in the earth's crust are Feldspar and Quartz, which are made up of Silica and Aluminium. Hence, option 2 is correct.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2012>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rock type formed through the deposits compression of elastic particles is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">anthracite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sandstone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mudstone</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mudstone is an extremely fine-grained sedimentary rock consisting of a mixture of clay and silt-sized particles.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2012>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following rock types is formed through the ejection of magma onto the surface of the earth?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Lignite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Granite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Slate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Basalt</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Basalt is a type of rock that is formed through the ejection of magma onto the surface of the earth. When magma reaches the earth's surface and cools quickly, it forms basalt. The other options, lignite, granite, and slate, are formed through different geological processes.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2012>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Rocks that are composed of particles derived from previously existing rocks are referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">metamorphic rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intrusive igneous rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sedimentary rocks</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extrusive igneous rocks</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mechanically formed sedimentary rocks are formed from the remains of either already established rocks.</div>", "topic": "PRATICAL GEOGRAPHY II : ROCKS"}, {"id": "objective>Geography>2012>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The coral deposits marked M are called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">barrier lakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barrier reefs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barrier shelves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barrier islands</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is separated from the coast by the deep channel/lagoon.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2012>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <strong>Use the diagram below to answer this question</strong> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The feature marked N is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">down-faulted block</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lagoon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">continental shell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deep sea</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is a shallow water zone that is close to and surrounds the continent.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2012>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ox-bow lake is usually located in a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volcanic crater</div>", "<div style=\"font-family:Cambria;font-size:17px;\">karst valley</div>", "<div style=\"font-family:Cambria;font-size:17px;\">river food pair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desert oasis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An ox-bow lake is a landform by river at the lower course.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2012>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The phenomenon of change in direction of wave fronts as they approach the sea shore is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wave refraction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tidal wave movement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">wave drifting </div>", "<div style=\"font-family:Cambria;font-size:17px;\">retrogradation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wave refraction is the process by which the direction of waves travel is changed as they pass from one medium to another, or when they pass across areas of different depth. As waves approach the shore, they are often refracted, or bent, and this is what the question refers to. Therefore, the correct answer is 'wave refraction'.</div>", "topic": "PRATICAL GEOGRAPHY II : WATER BODIES"}, {"id": "objective>Geography>2012>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The storm which occurs over the China Sea between latitudes 8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span> and 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>N and S of the equator is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tropical thunderstorm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tornado</div>", "<div style=\"font-family:Cambria;font-size:17px;\">typhoon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperate thunderstorm</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The storm which occurs over the China Sea between latitudes 8 degrees and 15 degrees N and S of the equator is a typhoon. A typhoon is a mature tropical cyclone that develops in the western part of the North Pacific Ocean between 180° and 100°E. This region is referred to as the Northwestern Pacific Basin, and is the most active tropical cyclone basin on Earth, accounting for almost one-third of the world's annual tropical cyclones. Therefore, the correct answer is 'typhoon'.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2012>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major characteristic of the tropical continental climate is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">occurrence of high diurnal temperatures throughout the year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of cloud cover throughout the year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevalence of high and constant temperatures throughout the year</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occurrence of alternating wet and dry seasons throughout the year</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tropical continental climate is characterized by the occurrence of alternating wet and dry seasons throughout the year. This is due to the movement of the Inter-Tropical Convergence Zone (ITCZ) which brings rainfall during its presence and dry conditions when it moves away.</div>", "topic": "PRATICAL GEOGRAPHY II : WEATHER AND CLIMATE"}, {"id": "objective>Geography>2012>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Plants that are highly tolerant of drought and can survive in dry habitats are referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mesophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tropophytes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">xerophytes</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Xerophtytes are drought-resistant plants. They are plants which are adapted to dry/desert areas. To survive these harsh conditions they have special features. For example, a cactus has white hairs which help to prevent water loss. Another example is Manzanita plants, which have a thick waxy coating and keep their leaves vertical to the sun.</div>", "topic": "PRATICAL GEOGRAPHY II : VEGETATION"}, {"id": "objective>Geography>2012>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An important characteristic of the B - horizon in tropical ferruginous soils is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eluviation of oxides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concentration of organic matter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">accumulation of oxides</div>", "<div style=\"font-family:Cambria;font-size:17px;\">predominance of parent material </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The B-horizon in tropical ferruginous soils is characterized by the accumulation of oxides. This is due to the process of leaching, where water carries soluble substances or small particles through the soil or other material. In the case of tropical ferruginous soils, iron and aluminium oxides are leached from the upper layers and accumulate in the B-horizon.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2012>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The texture of the soil depends on the constituent of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sand, silt and humus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand, clay and stones</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand, silt and clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sand, clay and quartz</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The texture of the soil is determined by the relative proportions of sand, silt, and clay it contains. This is known as the soil's mineral composition. Sand particles are the largest and tend to have good drainage but low water-holding capacity. Clay particles are the smallest and tend to have poor drainage but high water-holding capacity. Silt particles are intermediate in size and have properties in between sand and clay.</div>", "topic": "PRATICAL GEOGRAPHY II : SOILS"}, {"id": "objective>Geography>2012>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most significant economic use of clean water is for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drinking</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bathing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">recreation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">While all the options listed are uses of clean water, the most significant economic use is for drinking. This is because clean drinking water is a basic necessity for human survival and health. Without it, people cannot survive, and the cost of treating water-related diseases can be high. Therefore, ensuring a supply of clean drinking water is a top priority for any economy.</div>", "topic": "HUMAN GEOGRAPHY : WATER BODIES"}, {"id": "objective>Geography>2012>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major terrestrial ecosystems are often referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">biomes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biomass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasslands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boreal forests</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major terrestrial ecosystems are often referred to as biomes. A biome is a large community of plants and animals that occupies a distinct region. Biomes are defined by factors such as plant structures (such as trees, shrubs, and grasses), leaf types (such as broadleaf and needleleaf), plant spacing (forest, woodland, savanna), and climate. Unlike 'biomass', which refers to the total mass of organisms in a given area or volume, 'grasslands' and 'boreal forests' are examples of specific types of biomes.</div>", "topic": "HUMAN GEOGRAPHY : VEGETATION"}, {"id": "objective>Geography>2012>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Global warming directly result in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">melting ice cap and rising sea level</div>", "<div style=\"font-family:Cambria;font-size:17px;\">corrosion of roofing sheets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in atmosphere pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">population explosion and rapid urbanization</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It increases temperature and causes ice to melt, especially in polar regions thereby increasing the volume of water.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2012>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Accelerated soil erosion results from a combination of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bad farming practices and mulching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensive cultivation and cover crops</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bad farming practices and fertilizers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">intensive cultivation and overgrazing</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accelerated soil erosion is the removal of the top layer of soil faster than it can be replaced by natural processes. This is often caused by human activities such as intensive cultivation and overgrazing. Intensive cultivation often involves the use of heavy machinery and chemicals which can compact the soil and kill beneficial organisms that help to maintain soil structure. Overgrazing by livestock can remove vegetation cover and expose the soil to erosion by wind and water.</div>", "topic": "PRATICAL GEOGRAPHY II : ENVIRONMENTAL HAZARDS"}, {"id": "objective>Geography>2012>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following factors discourages population concentration in an area?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Grasslands</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Frozen soils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mineral deposits</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alluvial plains</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population concentration refers to the density of population in a specific area. Factors that discourage population concentration include harsh environmental conditions that make it difficult for human habitation and economic activities. Frozen soils, for instance, make it difficult to cultivate crops, build infrastructure, and carry out other economic activities. Therefore, areas with frozen soils tend to have lower population concentrations.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2012>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio of registered births to the population of women of child-bearing age is known as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fertility rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mortality rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morbidity rate</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fertility rate is the ratio of registered births to the population of women of child-bearing age. It is a demographic measure that indicates the number of live births per 1,000 women between the ages of 15 and 49 years in a given year.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2012>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of deaths, births, immigrants and emigrants over a specified time interval determines the population</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change</div>", "<div style=\"font-family:Cambria;font-size:17px;\">growth</div>", "<div style=\"font-family:Cambria;font-size:17px;\">structure</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Population change is determined by the number of births, deaths, immigrants, and emigrants over a specified time interval. It is the difference between the size of the population at the end and the beginning of the period.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2012>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is mainly associated with tourism?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rural settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commercial settlement</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Holiday resort</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Confluence town</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A holiday resort is mainly associated with tourism. It is a place where people go for holidays and relaxation. These places often have various attractions and amenities like beaches, mountains, spas, and other recreational facilities to attract tourists.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2012>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The merging of two or more extensive urban with areas results in a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">city </div>", "<div style=\"font-family:Cambria;font-size:17px;\">megalopolis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conurbation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metropolis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The merging of two or more extensive urban areas results in a conurbation. A conurbation is a region comprising a number of cities, large towns, and other urban areas that, through population growth and physical expansion, have merged to form one continuous urban and industrially developed area.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2012>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fertile plains are usually characterized by a pattern of settlement referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nucleated and concentric</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleated and elongated</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dispersed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nodal</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wide spaces are left in between settlements for farming.</div>", "topic": "HUMAN GEOGRAPHY : SETTLEMENT"}, {"id": "objective>Geography>2012>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An industry is optimally located where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit is minimized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost is maximized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">revenue is minimized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit is maximized </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The essence of the choice of location of industry is to minimize cost of production to maximize profit.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2012>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The lack of access to food in some parts of the world emanates from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low development of natural resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">educational inequality</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor transport system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic inequality's</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Places are inaccessible because of lack of good roads & other means of transportation.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2012>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The standard railway gauge is most common in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">North American and Europe </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Europe and Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Africa and North America</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South America and Africa</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The standard railway gauge, which is a measure of the distance between the inner sides of the two parallel rails that make up a railway track, is most common in North America and Europe. This gauge, also known as the 'Stephenson gauge' after George Stephenson, is 1,435 mm (4 ft 8 1⁄2 in) and is used by about 60% of the world's railways.</div>", "topic": "PRATICAL GEOGRAPHY II : LANDFORMS"}, {"id": "objective>Geography>2012>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">More than half of the world's trade is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">among developing countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">among developed countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">between developed and developing countries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">between Asiatic and African countries</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The largest trade route (shipping) is between U.S.A and Europe. Trans-pacific trading route is becoming increasing busy because it connects Japan and Western U.S.A.</div>", "topic": "REGIONAL GEOGRAPHY : INTERNATIONAL ECONOMIC COOPERATION IN WEST AFRICA ECOWAS"}, {"id": "objective>Geography>2012>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cane chairs, wooden masks and ornamental brass trays found in Nigeria are products of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturing industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">processing industries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">local crafts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">foreign lands</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cane chairs, wooden masks and ornamental brass trays found in Nigeria are products of local crafts. Local crafts refer to the production of goods by artisans, using traditional methods and materials. These crafts are often handmade and reflect the culture and traditions of the area.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2012>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is extracted in Nigeria by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drilling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mining</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dredging</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Petroleum is extracted in Nigeria by using a drilling rig. It is a machine that creates holes in the earth sub-surface. Apart from petroleum drilling, drilling rigs can also be used to drill water wells.</div>", "topic": "HUMAN GEOGRAPHY : SELECTED ECONOMIC ACTIVITIES"}, {"id": "objective>Geography>2012>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the major products that are taken to the markets from the south to the north are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">beef, onions, groundnuts and grains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plantains, garri, kolanuts and palm oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oranges, vegetables and beef</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potatoes, rice and onions</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, the major products that are taken to the markets from the south to the north are plantains, garri, kolanuts and palm oil. These are all products that are commonly grown and produced in the southern part of Nigeria and are transported to the north for sale.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2012>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The average elevation of the eastern scarpland of Nigeria ranges from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">300m - 4000m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">400m - 500m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500m - 600m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">600m - 700m</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Udi-Nsuka Plateau is the Eastern Scarpland & the height is from 300m - 600m.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2012>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The best methods of overcoming natural difficulties in Nigerian agriculture include </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">terracing, irrigation and research</div>", "<div style=\"font-family:Cambria;font-size:17px;\">irrigation, crop rotation and over-cultivation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">devegetation, research and mixed cropping</div>", "<div style=\"font-family:Cambria;font-size:17px;\">crop rotation, fire clearing and mixed cropping</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The best methods of overcoming natural difficulties in Nigerian agriculture include terracing, irrigation, and research. Terracing is the creation of flat areas on mountain slopes for cultivation, which helps prevent soil erosion. Irrigation is the artificial application of water to land to assist in the production of crops. Research is important for discovering and implementing new farming techniques and technologies. The other options include practices that can be harmful to the environment, such as over-cultivation and devegetation.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2012>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Lagos area has emerged as the most prominent destination for internal migration because it is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">close to the coast and is densely populated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">agriculturally  productive and close to the coast</div>", "<div style=\"font-family:Cambria;font-size:17px;\">on a high plain and is highly industrialized </div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly industrialized and highly urbanized</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lagos has emerged as the most prominent destination for internal migration in Nigeria because it is highly industrialized and highly urbanized. Industrialization refers to the process by which an economy is transformed from primarily agricultural to one based on the manufacturing of goods. Urbanization refers to the increasing number of people that live in urban areas. Lagos is Nigeria's largest city and its economic hub, with many industries and businesses located there.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2012>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inter-regional trade in Nigeria has mostly been promoted by the fact that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">different regions have different ethnic groups</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is improved inter-regional transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different regions produce different commodities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there is improved internal security</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">South West produces cocoa and kolanut, Mid West produces rubber, South East produces rubber and oil palm while North produces groundnut and cotton.</div>", "topic": "REGIONAL GEOGRAPHY : BROAD OUTLINE OF NIGERIA"}, {"id": "objective>Geography>2012>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The largest rift valley system in the world is in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">West Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">North Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">East Africa</div>", "<div style=\"font-family:Cambria;font-size:17px;\">South Africa</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The great East African rift valley system that stretches from the Red Sea to Zambia covering about 6,000km.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2012>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Sahel region of Africa is prone to be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">drought </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flooding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">earthquakes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">volcanoes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Sahel region of Africa is prone to drought. The Sahel is a transitional zone in Africa between the Sahara to the north and the more fertile region to the south, known as the Sudanian Savanna. The Sahel is characterized by its semi-arid climate, which makes it prone to drought.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2012>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Algeria's oil fields are located in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Hassi Messaoud</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Touggourt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marsa el Brega</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gulf of sirte</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Hassi Messaoud is a town in eastern Algeria known for its oil fields. It is the largest oil field in Algeria and has been a major contributor to the country's economy.</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2012>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major factors that account for the pattern of population distribution in West Africa are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transportation and communication</div>", "<div style=\"font-family:Cambria;font-size:17px;\">physical and economic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">historical and social</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social and political</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pattern of population distribution in West Africa is largely influenced by physical and economic factors. Physical factors include things like climate, soil fertility, and availability of water resources, while economic factors include things like job opportunities, infrastructure, and access to markets.</div>", "topic": "HUMAN GEOGRAPHY : POPULATION"}, {"id": "objective>Geography>2012>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The highest mountain in Africa is found in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cameroun</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethiopia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kenya</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rwanda</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is Mount Kilimanjaro at 5,895m. The highest mountain in Africa is found in Kenya</div>", "topic": "REGIONAL GEOGRAPHY : AFRICA ON BROAD OUTLINE"}, {"id": "objective>Geography>2012>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The two major plantation crops in West and East Africa respectively are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cocoa and coffee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cotton and coffee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cocoa and groundnut</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rubber and cotton</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The two major plantation crops in West and East Africa are cocoa and coffee respectively. West Africa, particularly Ivory Coast and Ghana, is known for its significant production of cocoa. On the other hand, East Africa, especially Ethiopia and Kenya, is renowned for its coffee production.</div>", "topic": "REGIONAL GEOGRAPHY : PLANTATION AGRICULTURE IN WEST AND EAST AFRICA"}, {"id": "objective>Geography>2012>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most densely populated river delta in Africa is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Niger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chari-Lagone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nile </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zambezi</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most densely populated river delta in Africa is the Nile Delta. The Nile Delta is located in Northern Egypt where the Nile River spreads out and drains into the Mediterranean Sea. It is one of the world's largest river deltas and it has supported a significant population for millennia.</div>", "topic": "REGIONAL GEOGRAPHY : POPULATION DISTRIBUTION IN WEST AFRICA"}];
